+    #[test]
+    fn complete_job_sets_progress_100() {
+        let mut id_gen = IdGenerator::new(1);
+        let (mut job, _) = create_job(&mut id_gen, "Test", JobKind::Task);
+
+        start_job(&mut job, &mut id_gen);
+
